// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {TestERC20} from "./TestERC20.sol";

interface ITestPairToken {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
}

contract TestV2Pair is TestERC20 {
    address public immutable token0;
    address public immutable token1;

    uint256 private reserve0;
    uint256 private reserve1;

    event Mint(address indexed sender, uint256 amount0, uint256 amount1);
    event Swap(address indexed sender, uint256 amount0Out, uint256 amount1Out, address indexed to);
    event Sync(uint256 reserve0, uint256 reserve1);

    constructor(address token0_, address token1_) TestERC20("Test V2 LP", "TV2-LP", 18) {
        require(token0_ != token1_, "IDENTICAL");
        require(token0_ != address(0), "ZERO");
        token0 = token0_;
        token1 = token1_;
    }

    function getReserves() external view returns (uint112, uint112, uint32) {
        require(reserve0 <= type(uint112).max && reserve1 <= type(uint112).max, "RESERVE_OVERFLOW");
        return (uint112(reserve0), uint112(reserve1), uint32(block.timestamp));
    }

    function mint(address to) external returns (uint256 liquidity) {
        uint256 balance0 = ITestPairToken(token0).balanceOf(address(this));
        uint256 balance1 = ITestPairToken(token1).balanceOf(address(this));
        uint256 amount0 = balance0 - reserve0;
        uint256 amount1 = balance1 - reserve1;

        if (totalSupply == 0) {
            liquidity = _sqrt(amount0 * amount1);
        } else {
            liquidity = _min(amount0 * totalSupply / reserve0, amount1 * totalSupply / reserve1);
        }

        require(liquidity > 0, "INSUFFICIENT_LIQUIDITY");
        _mint(to, liquidity);
        reserve0 = balance0;
        reserve1 = balance1;
        emit Mint(msg.sender, amount0, amount1);
        emit Sync(balance0, balance1);
    }

    function swap(uint256 amount0Out, uint256 amount1Out, address to) external {
        require(amount0Out > 0 || amount1Out > 0, "NO_OUTPUT");
        require(amount0Out < reserve0 && amount1Out < reserve1, "LIQUIDITY");
        if (amount0Out > 0) require(ITestPairToken(token0).transfer(to, amount0Out), "TOKEN0_OUT");
        if (amount1Out > 0) require(ITestPairToken(token1).transfer(to, amount1Out), "TOKEN1_OUT");

        uint256 balance0 = ITestPairToken(token0).balanceOf(address(this));
        uint256 balance1 = ITestPairToken(token1).balanceOf(address(this));
        reserve0 = balance0;
        reserve1 = balance1;
        emit Swap(msg.sender, amount0Out, amount1Out, to);
        emit Sync(balance0, balance1);
    }

    function skim(address to) external {
        uint256 balance0 = ITestPairToken(token0).balanceOf(address(this));
        uint256 balance1 = ITestPairToken(token1).balanceOf(address(this));
        if (balance0 > reserve0) require(ITestPairToken(token0).transfer(to, balance0 - reserve0), "TOKEN0_SKIM");
        if (balance1 > reserve1) require(ITestPairToken(token1).transfer(to, balance1 - reserve1), "TOKEN1_SKIM");
    }

    function _sqrt(uint256 y) private pure returns (uint256 z) {
        if (y == 0) return 0;
        z = y;
        uint256 x = y / 2 + 1;
        while (x < z) {
            z = x;
            x = (y / x + x) / 2;
        }
    }

    function _min(uint256 a, uint256 b) private pure returns (uint256) {
        return a < b ? a : b;
    }
}

project/contracts/test/TestV2Router.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {TestV2Factory} from "./TestV2Factory.sol";
import {TestV2Pair} from "./TestV2Pair.sol";

interface ITestRouterToken {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract TestV2Router {
    address public immutable factory;

    constructor(address factory_) {
        require(factory_ != address(0), "FACTORY_ZERO");
        factory = factory_;
    }

    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    ) external returns (uint256 amountA, uint256 amountB, uint256 liquidity) {
        require(block.timestamp <= deadline, "EXPIRED");
        address pair = TestV2Factory(factory).getPair(tokenA, tokenB);
        if (pair == address(0)) pair = TestV2Factory(factory).createPair(tokenA, tokenB);

        (uint256 reserveA, uint256 reserveB) = getReserves(tokenA, tokenB);
        (amountA, amountB) = _quoteAddLiquidity(amountADesired, amountBDesired, amountAMin, amountBMin, reserveA, reserveB);

        require(ITestRouterToken(tokenA).transferFrom(msg.sender, pair, amountA), "TOKEN_A_TRANSFER");
        require(ITestRouterToken(tokenB).transferFrom(msg.sender, pair, amountB), "TOKEN_B_TRANSFER");
        liquidity = TestV2Pair(pair).mint(to);
    }

    function getReserves(address tokenA, address tokenB) public view returns (uint256 reserveA, uint256 reserveB) {
        address pair = TestV2Factory(factory).getPair(tokenA, tokenB);
        if (pair == address(0)) return (0, 0);
        (uint112 reserve0, uint112 reserve1, ) = TestV2Pair(pair).getReserves();
        (address token0, ) = _sortTokens(tokenA, tokenB);
        (reserveA, reserveB) = tokenA == token0 ? (reserve0, reserve1) : (reserve1, reserve0);
    }

    function swapExactTokensForTokens(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 amountOut,
        address to
    ) external {
        address pair = TestV2Factory(factory).getPair(tokenIn, tokenOut);
        require(pair != address(0), "PAIR");
        require(ITestRouterToken(tokenIn).transferFrom(msg.sender, pair, amountIn), "TOKEN_IN_TRANSFER");
        address token0 = TestV2Pair(pair).token0();
        if (tokenOut == token0) {
            TestV2Pair(pair).swap(amountOut, 0, to);
        } else {
            TestV2Pair(pair).swap(0, amountOut, to);
        }
    }

    function quote(uint256 amountA, uint256 reserveA, uint256 reserveB) public pure returns (uint256) {
        require(amountA > 0, "AMOUNT");
        require(reserveA > 0 && reserveB > 0, "RESERVES");
        return amountA * reserveB / reserveA;
    }

    function _quoteAddLiquidity(
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        uint256 reserveA,
        uint256 reserveB
    ) private pure returns (uint256 amountA, uint256 amountB) {
        if (reserveA == 0 && reserveB == 0) {
            amountA = amountADesired;
            amountB = amountBDesired;
        } else {
            uint256 amountBOptimal = quote(amountADesired, reserveA, reserveB);
            if (amountBOptimal <= amountBDesired) {
                require(amountBOptimal >= amountBMin, "B_MIN");
                amountA = amountADesired;
                amountB = amountBOptimal;
            } else {
                uint256 amountAOptimal = quote(amountBDesired, reserveB, reserveA);
                require(amountAOptimal >= amountAMin, "A_MIN");
                amountA = amountAOptimal;
                amountB = amountBDesired;
            }
        }
        require(amountA >= amountAMin && amountB >= amountBMin, "MIN");
    }

    function _sortTokens(address tokenA, address tokenB) private pure returns (address token0, address token1) {
        require(tokenA != tokenB, "IDENTICAL");
        (token0, token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        require(token0 != address(0), "ZERO");
    }
}

